        insert into ehr_login (id, title, account, empID, 
	      workNo, name, isDisabled
	      )
	    values

          (#{item.id,jdbcType=INTEGER}, #{item.title,jdbcType=VARCHAR}, #{item.account,jdbcType=VARCHAR}, #{item.empID,jdbcType=INTEGER}, 
          #{item.workNo,jdbcType=VARCHAR}, #{item.name,jdbcType=VARCHAR}, #{item.isDisabled,jdbcType=VARCHAR}
          )

        ON DUPLICATE KEY UPDATE title = VALUES(title), account = VALUES(account), empID = VALUES(empID), 
            workNo = VALUES(workNo), name = VALUES(name), isDisabled = VALUES(isDisabled)

        insert into ehr_holiday (id, date, isHoliday)
	    values

          (#{item.id,jdbcType=INTEGER}, #{item.date,jdbcType=TIMESTAMP}, #{item.isHoliday,jdbcType=BIT}
          )

        ON DUPLICATE KEY UPDATE date = VALUES(date), isHoliday = VALUES(isHoliday)
